sql:
SELECT COUNT(DISTINCT player_id) AS player_count
FROM player_leaderboards
WHERE leaderboard_id = 1 AND player_leaderboard_status = 'active';

external_knowledge:
- 'Best scores' here are interpreted as the highest scores; 
- 'Active scores' indicate that only scores currently in use or recognized are considered;
- 'Top five' implies that only the highest five scores, if available, per player are considered for the answer.

sql:
SELECT AVG(score) AS average_score
FROM scores
WHERE player_id = 1;

SELECT player_id, COUNT(rank) AS rank_count
FROM ranks
GROUP BY player_id;

SELECT AVG(score) AS average_score
FROM scores
WHERE level_id = 1;

